namespace sv_4545e84fb4d64e2c9f68c7b900152231.Services;

public class WarehouseInfo
{
    public required string Id { get; init; }
    public required string Name { get; init; }
}

public class WarehouseState
{
    public static readonly IReadOnlyList<WarehouseInfo> AvailableWarehouses =
    [
        new() { Id = "wh-east", Name = "Warehouse East" },
        new() { Id = "wh-west", Name = "Warehouse West" },
        new() { Id = "wh-north", Name = "Warehouse North" },
        new() { Id = "wh-central", Name = "Warehouse Central" },
