@code {
    [CascadingParameter]
    private WarehouseState State { get; set; } = default!;

    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastCheck;
    private string _lastWarehouseId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _lastWarehouseId = State.SelectedWarehouseId;
        await StartPollingAsync();
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed via cascading parameter — restart polling
        if (_lastWarehouseId != State.SelectedWarehouseId)
        {
            _lastWarehouseId = State.SelectedWarehouseId;
            await StopPollingAsync();
            await StartPollingAsync();
        }
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;

        // Fetch immediately on start
        await PollOnceAsync();

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await PollOnceAsync();
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse switch
        }
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(State.SelectedWarehouseId);
        AlertService.UpdateCount(count);
        _lastCheck = DateTime.Now;
    }

    private async Task StopPollingAsync()
    {
        _isPolling = false;
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopPollingAsync();
    }
}

