@page "/dashboard"
@using sv_4545e84fb4d64e2c9f68c7b900152231.Services
@inject InventoryAlertService AlertService
@implements IAsyncDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard — @State.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Managing: <strong>@State.SelectedWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low-Stock Alerts</h5>
                <p class="display-4 fw-bold">@AlertService.LowStockCount</p>
                <p class="text-muted">
                    Items below minimum level
                    <br />
                    <small>Refreshes every 10 seconds</small>
                </p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Active Warehouse</h5>
                <p class="display-6">@State.SelectedWarehouseName</p>
                <p class="text-muted">
                    <small>ID: @State.SelectedWarehouseId</small>
                </p>
            </div>
        </div>
    </div>
    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">
                    @if (_isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-secondary">● Stopped</span>
                    }
                </p>
                <p class="text-muted">
                    <small>Last check: @_lastCheck?.ToString("HH:mm:ss")</small>
                </p>
            </div>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseState State { get; set; } = default!;

    private CancellationTokenSource? _cts;
    private bool _isPolling;
    private DateTime? _lastCheck;
    private string _lastWarehouseId = string.Empty;

    protected override async Task OnInitializedAsync()
    {
        _lastWarehouseId = State.SelectedWarehouseId;
        await StartPollingAsync();
    }

    protected override async Task OnParametersSetAsync()
    {
        // Warehouse changed via cascading parameter — restart polling
        if (_lastWarehouseId != State.SelectedWarehouseId)
        {
            _lastWarehouseId = State.SelectedWarehouseId;
            await StopPollingAsync();
            await StartPollingAsync();
        }
    }

    private async Task StartPollingAsync()
    {
        _cts = new CancellationTokenSource();
        _isPolling = true;

        // Fetch immediately on start
        await PollOnceAsync();

        _ = PollLoopAsync(_cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken ct)
    {
        using var timer = new PeriodicTimer(TimeSpan.FromSeconds(10));

        try
        {
            while (await timer.WaitForNextTickAsync(ct))
            {
                await InvokeAsync(async () =>
                {
                    await PollOnceAsync();
                    StateHasChanged();
                });
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on dispose / warehouse switch
        }
    }

    private async Task PollOnceAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(State.SelectedWarehouseId);
        AlertService.UpdateCount(count);
        _lastCheck = DateTime.Now;
    }

    private async Task StopPollingAsync()
    {
        _isPolling = false;
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopPollingAsync();
    }
}

